def weight_gib(parameters_billions: float, bits_per_weight: int) -> float:
    bytes_required = parameters_billions * 1_000_000_000 * bits_per_weight / 8
    return bytes_required / (1024 ** 3)

for bits in (16, 8, 4):
    floor = weight_gib(parameters_billions=70, bits_per_weight=bits)
    print(f"{bits}-bit weights only: {floor:.1f} GiB")

